import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({
  refreshKey = 0,
}) {
  const [tickets, setTickets] =
    useState([]);

  const [
    ticketIdSearch,
    setTicketIdSearch,
  ] = useState('');

  const [
    departmentFilter,
    setDepartmentFilter,
  ] = useState('');

  const [
    moduleFilter,
    setModuleFilter,
  ] = useState('');

  const [
    submoduleFilter,
    setSubmoduleFilter,
  ] = useState('');

  const [
    createdFromDate,
    setCreatedFromDate,
  ] = useState('');

  const [
    createdToDate,
    setCreatedToDate,
  ] = useState('');

  const [departments, setDepartments] =
    useState([]);

  const [modules, setModules] =
    useState([]);

  const [submodules, setSubmodules] =
    useState([]);

  const [page, setPage] =
    useState(1);

  const [count, setCount] =
    useState(0);

  const [nextPage, setNextPage] =
    useState(null);

  const [previousPage, setPreviousPage] =
    useState(null);

  // LOAD DROPDOWNS
  const loadDropdowns =
    async () => {
      try {
        const [
          deptRes,
          moduleRes,
          submoduleRes,
        ] = await Promise.all([
          api.get(
            '/masters/departments/'
          ),
          api.get(
            '/masters/modules/'
          ),
          api.get(
            '/masters/submodules/'
          ),
        ]);

        setDepartments(
          deptRes.data.results ||
            deptRes.data ||
            []
        );

        setModules(
          moduleRes.data.results ||
            moduleRes.data ||
            []
        );

        setSubmodules(
          submoduleRes.data.results ||
            submoduleRes.data ||
            []
        );
      } catch (err) {
        console.error(err);
      }
    };

  // FILTER MODULES
  const filteredModules =
    !departmentFilter
      ? modules
      : modules.filter(
          (module) =>
            Number(
              module.department ||
                module.department_id
            ) ===
            Number(
              departmentFilter
            )
        );

  // FILTER SUBMODULES
  const filteredSubmodules =
    !moduleFilter
      ? submodules
      : submodules.filter(
          (submodule) =>
            Number(
              submodule.module
            ) ===
            Number(
              moduleFilter
            )
        );

  // LOAD TICKETS
  const loadTickets =
    async (pageNo = page) => {
      try {
        const params = {
          page: pageNo,
        };

        if (ticketIdSearch) {
          params.ticket_id =
            ticketIdSearch;
        }

        if (
          departmentFilter
        ) {
          params.department =
            departmentFilter;
        }

        if (moduleFilter) {
          params.module =
            moduleFilter;
        }

        if (
          submoduleFilter
        ) {
          params.submodule =
            submoduleFilter;
        }

        // DATE FILTER
        if (
          createdFromDate &&
          createdToDate
        ) {
          params.created_from =
            createdFromDate;
          params.created_to =
            createdToDate;
        } else if (
          createdFromDate
        ) {
          params.created_at =
            createdFromDate;
        }

        const res =
          await api.get(
            '/tickets/',
            { params }
          );

        const data =
          res.data;

        setTickets(
          data.results || []
        );

        setCount(
          data.count || 0
        );

        setNextPage(
          data.next
        );

        setPreviousPage(
          data.previous
        );
      } catch (err) {
        console.error(
          'Ticket load failed:',
          err
        );
      }
    };

  useEffect(() => {
    loadDropdowns();
  }, []);

  useEffect(() => {
    loadTickets(page);
  }, [
    refreshKey,
    page,
    ticketIdSearch,
    departmentFilter,
    moduleFilter,
    submoduleFilter,
    createdFromDate,
    createdToDate,
  ]);

  // RESET
  const handleResetFilters =
    () => {
      setTicketIdSearch('');
      setDepartmentFilter(
        ''
      );
      setModuleFilter('');
      setSubmoduleFilter(
        ''
      );
      setCreatedFromDate(
        ''
      );
      setCreatedToDate('');
      setPage(1);
    };

  // EXPORT EXCEL
  const handleExport =
    async () => {
      try {
        const params = {};

        if (ticketIdSearch)
          params.ticket_id =
            ticketIdSearch;

        if (
          departmentFilter
        )
          params.department =
            departmentFilter;

        if (moduleFilter)
          params.module =
            moduleFilter;

        if (
          submoduleFilter
        )
          params.submodule =
            submoduleFilter;

        if (
          createdFromDate &&
          createdToDate
        ) {
          params.created_from =
            createdFromDate;
          params.created_to =
            createdToDate;
        } else if (
          createdFromDate
        ) {
          params.created_at =
            createdFromDate;
        }

        const res =
          await api.get(
            '/tickets/export_excel/',
            {
              params,
              responseType:
                'blob',
            }
          );

        const url =
          window.URL.createObjectURL(
            new Blob([
              res.data,
            ])
          );

        const link =
          document.createElement(
            'a'
          );

        link.href = url;

        link.setAttribute(
          'download',
          'tickets.xlsx'
        );

        document.body.appendChild(
          link
        );

        link.click();
        link.remove();
      } catch (err) {
        console.error(
          'Export failed:',
          err
        );
      }
    };

  const totalPages =
    Math.ceil(count / 8);

  return (
    <div>
      {/* FILTERS */}
      <div className="row mb-3 g-2">

        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={ticketIdSearch}
            onChange={(e) =>
              setTicketIdSearch(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={departmentFilter}
            onChange={(e) => {
              setDepartmentFilter(
                e.target.value
              );
              setModuleFilter('');
              setSubmoduleFilter(
                ''
              );
            }}
          >
            <option value="">
              All Departments
            </option>

            {departments.map(
              (dept) => (
                <option
                  key={dept.id}
                  value={dept.id}
                >
                  {
                    dept.department_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={moduleFilter}
            onChange={(e) =>
              setModuleFilter(
                e.target.value
              )
            }
          >
            <option value="">
              All Modules
            </option>

            {filteredModules.map(
              (module) => (
                <option
                  key={module.id}
                  value={module.id}
                >
                  {
                    module.module_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              submoduleFilter
            }
            onChange={(e) =>
              setSubmoduleFilter(
                e.target.value
              )
            }
          >
            <option value="">
              All Submodules
            </option>

            {filteredSubmodules.map(
              (
                submodule
              ) => (
                <option
                  key={
                    submodule.id
                  }
                  value={
                    submodule.id
                  }
                >
                  {
                    submodule.submodule_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={
              createdFromDate
            }
            onChange={(e) =>
              setCreatedFromDate(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={
              createdToDate
            }
            onChange={(e) =>
              setCreatedToDate(
                e.target.value
              )
            }
          />
        </div>

      </div>

      <div className="mb-3 d-flex gap-2">
        <button
          className="btn btn-secondary"
          onClick={
            handleResetFilters
          }
        >
          Reset
        </button>

        <button
          className="btn btn-success"
          onClick={
            handleExport
          }
        >
          Export Excel
        </button>
      </div>

      {/* TABLE */}
      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Module</th>
              <th>Submodule</th>
              <th>Subject</th>
              <th>Status</th>
              <th>Created Date</th>

            </tr>
          </thead>

          <tbody>
            {tickets.length >
            0 ? (
              tickets.map(
                (ticket) => (
                  <tr
                    key={
                      ticket.id
                    }
                  >
                    <td>
                      {
                        ticket.ticket_id
                      }
                    </td>
                    <td>
                      {
                        ticket.department_name
                      }
                    </td>
                    <td>
                      {
                        ticket.module_name
                      }
                    </td>
                    <td>
                      {
                        ticket.submodule_name
                      }
                    </td>
                    <td>
                      {
                        ticket.subject
                      }
                    </td>
                    <td>
                      {ticket.created_at
                        ? new Date(
                            ticket.created_at
                          ).toLocaleDateString()
                        : '-'}
                    </td>
                  </tr>
                )
              )
            ) : (
              <tr>
                <td
                  colSpan="6"
                  className="text-center"
                >
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
